+        final Map<String, AnnotatedField> currentGetters = new LinkedHashMap<>();
+        for (final AnnotatedField field : fields) {
+            if (!rejected.contains(field.fieldName())) {
+                currentGetters.put(field.getterName(), field);
+            }
+        }
