+                                    + derivedType + " and " + baseType,
+                            findFieldElement(enclosingClass, derivedField.fieldName()));
+                    rejected.add(derivedField.fieldName());
+                }
+            }
+            superMirror = superElement.getSuperclass();
+        }
+    }
